DROP TABLE IF EXISTS `participantstats`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `participantstats` (
  `StatID` int NOT NULL AUTO_INCREMENT,
  `MatchID` int NOT NULL,
  `PlayerID` int NOT NULL,
  `ChampID` int NOT NULL,
  `Kills` int DEFAULT NULL,
  `Deaths` int DEFAULT NULL,
  `Assists` int DEFAULT NULL,
  `GoldEarned` int DEFAULT NULL,
  `GoldSpent` int DEFAULT NULL,
  `VisionScore` int DEFAULT NULL,
  `MinionsKilled` int DEFAULT NULL,
  `DamageDealt` int DEFAULT NULL,
  `Team` enum('BLUE','RED') NOT NULL,
  `Level` int DEFAULT NULL,
  `PlayerWon` tinyint(1) DEFAULT NULL,
  `Role` varchar(20) DEFAULT NULL,
  PRIMARY KEY (`StatID`),
  KEY `MatchID` (`MatchID`),
  KEY `PlayerID` (`PlayerID`),
  KEY `participantstats_ibfk_3` (`ChampID`),
  CONSTRAINT `participantstats_ibfk_1` FOREIGN KEY (`MatchID`) REFERENCES `matches` (`MatchID`),
  CONSTRAINT `participantstats_ibfk_2` FOREIGN KEY (`PlayerID`) REFERENCES `players` (`PlayerID`),
  CONSTRAINT `participantstats_ibfk_3` FOREIGN KEY (`ChampID`) REFERENCES `champions` (`ChampID`)
) ENGINE=InnoDB AUTO_INCREMENT=7391 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

